/* Set the day as we now now the user has selected a date for the Hearing to be heard on.
				  Date on represents the value entered but as 2004-12-25.
				*/				
				var dateOn = Services.getValue(HearingDate2.dataBinding);
				if (null != dateOn)
				{
					var day = setDay(dateOn);
					Services.setValue(HearingDay2.dataBinding, day);
				}
				else
				{	Services.setValue(HearingDay2.dataBinding, "");
				}

Javascript.miscCode:
/*
 * Method returns a day for a supplied date
 * pDate The date in the format 2004-12-20
 */
function setDay(pDate)
{
	var day = ""; // Day as text.  This is returned	
	var theDate;
	
	//Constants for switch statement
	var SUN = 0;
	var MON = 1;
	var TUE = 2;
	var WED = 3;
	var THU = 4;
	var FRI = 5;
	var SAT = 6;
		
	if(pDate != null && pDate != ""){		
		theDate = setDateAsObject(pDate);		
		var dayAsInt = theDate.getDay();		
		switch (dayAsInt)
		{   	
			case SUN:
		  	{
		  		day = "SUNDAY";
		  		break;
		  	}
		  	case MON:
		  	{
		  		day = "MONDAY";
		  		break;
		  	}
		  	case TUE:
		  	{
		  		day = "TUESDAY";
		  		break;
		  	}
		  	case WED:
		  	{
		  		day = "WEDNESDAY";
		  		break;
		  	}
		  	case THU:
		  	{
		  		day = "THURSDAY";
		  		break;
		  	}
		  	case FRI:
		  	{
		  		day = "FRIDAY";
		  		break;
		  	}
		  	case SAT:
		  	{
		  		day = "SATURDAY";
		  		break;
		  	}
		  	default:
		  	{
		  		day = "";
		  		break;
		  	}  	
	  	}// END OF switch (dayAsInt)	  	
  	} // end of if block
  	return day;  	
} // END OF setDay()

/*
 * Method returns a date as a javascript Date object for a supplied date.
 * pDate  - a date in the format 2004-12-20 or 2004/12/20
 */
function setDateAsObject(pDate)
{
	// need to split the date value into something the Date object recognises
	var tmpYear;
	var tmpMth;
	var tmpDate;
	
	if(pDate != null && pDate != ""){
		// get the year etc from string
		tmpYear = pDate.substr(0,4);
		tmpMth = pDate.substr(5,2);
		tmpMth = tmpMth - 1;
		tmpDate = pDate.substr(8,2);		

	}// end of if(pDate != null && pDate != ""){
	var theDate = new Date(tmpYear, tmpMth ,tmpDate);	
	return theDate;
}
